import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery, DashboardData, MetricSummary } from '../../src/models/analytics.js';

describe('AnalyticsService', () => {
  let db: Database;
  let analyticsRepo: AnalyticsRepository;
  let service: AnalyticsService;

  const defaultQuery: AnalyticsQuery = {
    startDate: new Date('2026-01-01'),
    endDate: new Date('2026-01-31'),
    granularity: 'day' as const,
  };

  beforeEach(() => {
    db = new Database();
    analyticsRepo = new AnalyticsRepository(db);
    service = new AnalyticsService(analyticsRepo);
  });

  function insertOrder(overrides: Record<string, unknown> = {}) {
    const id = overrides['id'] as string ?? `order-${Math.random().toString(36).slice(2)}`;
    db.insert('orders', {
      id,
      userId: 'user-1',
      items: [{ productId: 'prod-1', name: 'Widget', quantity: 2, unitPrice: 25 }],
      total: 50,
      status: 'confirmed',
      createdAt: new Date('2026-01-15').toISOString(),
      updatedAt: new Date('2026-01-15').toISOString(),
      ...overrides,
    });
  }

  function insertUser(overrides: Record<string, unknown> = {}) {
    const id = overrides['id'] as string ?? `user-${Math.random().toString(36).slice(2)}`;
    db.insert('users', {
      id,
      name: 'Test User',
      email: `${id}@test.com`,
      role: 'member',
      createdAt: new Date('2026-01-10').toISOString(),
      updatedAt: new Date('2026-01-10').toISOString(),
      ...overrides,
    });
  }

  // ── getDashboard ────────────────────────────────────────────────

  describe('getDashboard', () => {
    it('should return dashboard data with correct shape', () => {
      const dashboard: DashboardData = service.getDashboard(defaultQuery);

      expect(dashboard.query).toEqual(defaultQuery);
      expect(dashboard.metrics).toHaveLength(4);
      expect(dashboard.ordersByStatus).toHaveLength(5);
      expect(dashboard.revenueOverTime).toBeDefined();
      expect(dashboard.revenueOverTime.metric).toBe('revenue');
      expect(dashboard.newUsersOverTime).toBeDefined();
      expect(dashboard.newUsersOverTime.metric).toBe('newUsers');
    });

    it('should include all four metric types', () => {
      const dashboard = service.getDashboard(defaultQuery);
      const types = dashboard.metrics.map((m) => m.type);

      expect(types).toContain('revenue');
      expect(types).toContain('orders');
      expect(types).toContain('users');
      expect(types).toContain('average-order-value');
    });

    it('should aggregate order data into status breakdown', () => {
      insertOrder({ id: 'o1', status: 'confirmed', total: 100 });
      insertOrder({ id: 'o2', status: 'confirmed', total: 200 });
      insertOrder({ id: 'o3', status: 'pending', total: 50 });

      const dashboard = service.getDashboard(defaultQuery);
      const confirmed = dashboard.ordersByStatus.find((s) => s.status === 'confirmed');
      const pending = dashboard.ordersByStatus.find((s) => s.status === 'pending');

      expect(confirmed?.count).toBe(2);
      expect(confirmed?.revenue).toBe(300);
      expect(pending?.count).toBe(1);
      expect(pending?.revenue).toBe(50);
    });

    it('should return empty metrics and time series with no data', () => {
      const dashboard = service.getDashboard(defaultQuery);

      expect(dashboard.metrics.every((m) => m.currentValue === 0)).toBe(true);
      expect(dashboard.revenueOverTime.points).toHaveLength(0);
      expect(dashboard.newUsersOverTime.points.length).toBeGreaterThan(0);
    });

    it('should include all five order statuses in breakdown even with no orders', () => {
      const dashboard = service.getDashboard(defaultQuery);
      const statuses = dashboard.ordersByStatus.map((s) => s.status);

      expect(statuses).toEqual(['pending', 'confirmed', 'shipped', 'delivered', 'cancelled']);
      expect(dashboard.ordersByStatus.every((s) => s.count === 0 && s.revenue === 0)).toBe(true);
    });

    it('should populate revenue time series from orders', () => {
      insertOrder({ id: 'o1', total: 100, createdAt: new Date('2026-01-05').toISOString() });
      insertOrder({ id: 'o2', total: 200, createdAt: new Date('2026-01-05').toISOString() });
      insertOrder({ id: 'o3', total: 50, createdAt: new Date('2026-01-20').toISOString() });

      const dashboard = service.getDashboard(defaultQuery);

      expect(dashboard.revenueOverTime.points.length).toBeGreaterThan(0);
      const totalRevenue = dashboard.revenueOverTime.points.reduce((s, p) => s + p.value, 0);
      expect(totalRevenue).toBe(350);
    });

    it('should populate new users time series', () => {
      insertUser({ id: 'u1', createdAt: new Date('2026-01-05').toISOString() });
