    it('should respect the limit parameter', () => {
      insertOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'A', quantity: 1, unitPrice: 100 },
          { productId: 'p2', name: 'B', quantity: 1, unitPrice: 50 },
