      insertOrder({ id: 'o2', total: 200, createdAt: new Date('2026-02-15').toISOString() });
      insertOrder({ id: 'o3', total: 300, createdAt: new Date('2026-03-15').toISOString() });

      const metric = service.getMetric('revenue', monthQuery);
      expect(metric.timeSeries.points.length).toBeGreaterThanOrEqual(3);
      const totalRevenue = metric.timeSeries.points.reduce((s, p) => s + p.value, 0);
      expect(totalRevenue).toBe(600);
    });

    it('should produce time series points with Date timestamps', () => {
      insertOrder({ id: 'o1', total: 100 });

      const metric = service.getMetric('revenue', defaultQuery);
      for (const point of metric.timeSeries.points) {
        expect(point.timestamp).toBeInstanceOf(Date);
        expect(typeof point.value).toBe('number');
      }
    });
  });

  // ── Edge cases ──────────────────────────────────────────────────

  describe('edge cases', () => {
    it('should handle a query where startDate equals endDate', () => {
      const sameDay: AnalyticsQuery = {
        startDate: new Date('2026-01-15'),
        endDate: new Date('2026-01-15'),
        granularity: 'day',
      };
      insertOrder({ id: 'o1', total: 100, createdAt: new Date('2026-01-15').toISOString() });

      const metric = service.getMetric('revenue', sameDay);
      expect(metric.currentValue).toBe(100);
    });

    it('should handle orders with zero total', () => {
      insertOrder({ id: 'o1', total: 0 });

      const metric = service.getMetric('revenue', defaultQuery);
      expect(metric.currentValue).toBe(0);

      const orderMetric = service.getMetric('orders', defaultQuery);
      expect(orderMetric.currentValue).toBe(1);

      const avgMetric = service.getMetric('average-order-value', defaultQuery);
      expect(avgMetric.currentValue).toBe(0);
    });

    it('should handle large number of orders', () => {
      for (let i = 0; i < 200; i++) {
        insertOrder({
          id: `o${i}`,
