      const metric = service.getMetric('revenue', defaultQuery);
      expect(metric.currentValue).toBeCloseTo(100, 2);
    });

    it('should handle all order statuses in breakdown', () => {
      const statuses = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'] as const;
      statuses.forEach((status, i) => {
        insertOrder({ id: `o${i}`, status, total: (i + 1) * 10 });
