      const dashboard = service.getDashboard(defaultQuery);
      for (let i = 0; i < statuses.length; i++) {
        const entry = dashboard.ordersByStatus.find((s) => s.status === statuses[i]);
        expect(entry?.count).toBe(1);
        expect(entry?.revenue).toBe((i + 1) * 10);
