  // ── AnalyticsRepository ─────────────────────────────────────────

  describe('AnalyticsRepository', () => {
    it('should return empty arrays when no data exists', () => {
      const orders = analyticsRepo.findOrdersInRange(new Date('2026-01-01'), new Date('2026-01-31'));
