      const orders = analyticsRepo.findOrdersInRange(new Date('2026-01-01'), new Date('2026-01-31'));
      const ids = orders.map((o) => o.id);

      expect(ids).toContain('o-start');
      expect(ids).toContain('o-mid');
      expect(ids).toContain('o-end');
      expect(ids).not.toContain('o-before');
      expect(ids).not.toContain('o-after');
    });

