      insertOrder({ id: 'o1' });
      const orders = analyticsRepo.findOrdersInRange(new Date('2026-01-01'), new Date('2026-01-31'));
      expect(orders[0].createdAt).toBeInstanceOf(Date);
    });

    it('should parse order items as arrays', () => {
      insertOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'A', quantity: 1, unitPrice: 10 },
          { productId: 'p2', name: 'B', quantity: 2, unitPrice: 20 },
