      expect(orders[0].items).toHaveLength(2);
    });

    it('should count orders by status', () => {
      insertOrder({ id: 'o1', status: 'pending' });
      insertOrder({ id: 'o2', status: 'pending' });
      insertOrder({ id: 'o3', status: 'confirmed' });

      const counts = analyticsRepo.countOrdersByStatus();
      expect(counts.pending).toBe(2);
      expect(counts.confirmed).toBe(1);
      expect(counts.shipped).toBe(0);
    });

    it('should count orders by status within date range', () => {
      insertOrder({ id: 'o-in', status: 'pending', createdAt: new Date('2026-01-15').toISOString() });
      insertOrder({ id: 'o-out', status: 'pending', createdAt: new Date('2026-06-01').toISOString() });

      const counts = analyticsRepo.countOrdersByStatus(new Date('2026-01-01'), new Date('2026-01-31'));
      expect(counts.pending).toBe(1);
    });

    it('should sum revenue by status', () => {
      insertOrder({ id: 'o1', status: 'confirmed', total: 100 });
      insertOrder({ id: 'o2', status: 'confirmed', total: 250 });
      insertOrder({ id: 'o3', status: 'pending', total: 75 });

      const revenue = analyticsRepo.sumRevenueByStatus();
      expect(revenue.confirmed).toBe(350);
      expect(revenue.pending).toBe(75);
      expect(revenue.shipped).toBe(0);
    });

    it('should sum revenue by status within date range', () => {
      insertOrder({ id: 'o-in', status: 'confirmed', total: 100, createdAt: new Date('2026-01-15').toISOString() });
      insertOrder({ id: 'o-out', status: 'confirmed', total: 999, createdAt: new Date('2026-06-01').toISOString() });

      const revenue = analyticsRepo.sumRevenueByStatus(new Date('2026-01-01'), new Date('2026-01-31'));
      expect(revenue.confirmed).toBe(100);
    });

    it('should filter users by creation date range', () => {
      insertUser({ id: 'u-before', createdAt: new Date('2025-12-31').toISOString() });
      insertUser({ id: 'u-in', createdAt: new Date('2026-01-10').toISOString() });
      insertUser({ id: 'u-after', createdAt: new Date('2026-02-01').toISOString() });

      const users = analyticsRepo.findUsersCreatedInRange(new Date('2026-01-01'), new Date('2026-01-31'));
      expect(users).toHaveLength(1);
      expect(users[0].id).toBe('u-in');
    });
  });
});

