      expect(typeof metric.previousValue).toBe('number');
      expect(typeof metric.changePercent).toBe('number');
    });

    it('should compute revenue from orders in range', () => {
      insertOrder({ id: 'o1', total: 100 });
      insertOrder({ id: 'o2', total: 250 });

      const metric = service.getMetric('revenue', defaultQuery);
      expect(metric.currentValue).toBe(350);
    });

    it('should compute order count', () => {
      insertOrder({ id: 'o1' });
      insertOrder({ id: 'o2' });
      insertOrder({ id: 'o3' });

      const metric = service.getMetric('orders', defaultQuery);
      expect(metric.currentValue).toBe(3);
    });

    it('should compute user count', () => {
      insertUser({ id: 'u1' });
      insertUser({ id: 'u2' });

      const metric = service.getMetric('users', defaultQuery);
      expect(metric.currentValue).toBe(2);
    });

    it('should compute average order value', () => {
      insertOrder({ id: 'o1', total: 100 });
      insertOrder({ id: 'o2', total: 200 });

      const metric = service.getMetric('average-order-value', defaultQuery);
      expect(metric.currentValue).toBe(150);
    });

    it('should handle average-order-value with zero orders', () => {
